use std::sync::{Arc, Mutex};

fn handle_concurrent_inventory_updates(mutex: &Mutex<i32>) {
    let mut inventory = Arc::clone(&mutex);
    // Thread 1
    let thread1 = thread::spawn(move || {
        let mut inventory = Arc::get_mut(&inventory).unwrap();
        *inventory -= 1;
    });
    
    // Thread 2
    let thread2 = thread::spawn(move || {
        let mut inventory = Arc::get_mut(&inventory).unwrap();
        *inventory -= 1;
    });
    
    // Wait for threads to finish
    thread1.join().unwrap();
    thread2.join().unwrap();
}